// Constants
const clientId = 'your_client_id';
const clientSecret = 'your_client_secret';
const redirectUri = 'your_redirect_uri';
const authorizationEndpoint = 'your_authorization_endpoint';
const tokenEndpoint = 'your_token_endpoint';

// Function to initiate the OAuth authorization flow
function login() {
  const authUrl = `${authorizationEndpoint}?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=code`;
  window.location.href = authUrl;
}

// Function to handle the OAuth callback
function callback(hash) {
  const code = hash.split('=')[1];
  fetchToken(code);
}

// Function to fetch the access token
function fetchToken(code) {
  const data = {
    client_id: clientId,
    client_secret: clientSecret,
    redirect_uri: redirectUri,
    grant_type: 'authorization_code',
    code: code,
  };

  fetch(tokenEndpoint, {
    method: 'POST',
    body: JSON.stringify(data),
    headers: {
      'Content-Type': 'application/json',
    },
  })
    .then(response => response.json())
    .then(token => {
      localStorage.setItem('accessToken', token.access_token);
      // Redirect to the protected resource
      window.location.href = '/protected-resource';
    });
}

// Check for hash in the URL and handle callback if present
if (window.location.hash) {
  callback(window.location.hash);
}